const menu=document.querySelector('[data-menu]'),open=document.querySelector('[data-menu-open]'),close=document.querySelector('[data-menu-close]'),result=document.querySelector('[data-result]');let previous;function hide(){menu.close();open.setAttribute('aria-expanded','false');previous?.focus()}open?.addEventListener('click',()=>{previous=document.activeElement;menu.showModal();open.setAttribute('aria-expanded','true');close.focus()});close?.addEventListener('click',hide);menu?.addEventListener('cancel',event=>{event.preventDefault();hide()});menu?.addEventListener('click',event=>{if(event.target===menu)hide()});document.querySelectorAll('dialog a').forEach(link=>link.addEventListener('click',hide));document.querySelector('.desk')?.insertAdjacentHTML('beforeend','<a href="#app">Appen</a>');document.querySelector('.resource-stack')?.insertAdjacentHTML('afterbegin','<a href="#help"><span>GUIDE · HACCP</span><b>HACCP och riskstyrning</b><small>Förstå arbetskedjan innan du börjar med underlaget.</small><i>Öppna HACCP-navet</i></a>');const candidate=[...document.querySelectorAll('.resource-stack a')].find(link=>link.textContent.includes('Faroanalys'));if(candidate){candidate.querySelector('span').textContent='FRAMTIDA VERKTYGSKANDIDAT · HACCP';candidate.querySelector('small').textContent='Skapa ett granskningsbart första utkast, inte en färdig plan.'}document.querySelector('[data-search]')?.addEventListener('submit',event=>{event.preventDefault();const term=event.currentTarget.querySelector('input').value.trim();result.textContent=term?`Prototypresultat för ”${term}”. Sökfrasen är bevarad inför resursytan.`:'';result.tabIndex=-1;result.focus()});const style=document.createElement('style');style.textContent='[data-result]:not(:empty){margin-top:10px!important;padding:11px;border:1px solid var(--orange);background:var(--paper);color:var(--ink)!important;font-weight:700}@media(max-width:649px){.board-main{grid-template-columns:1fr}.board-main aside{display:none}}@media(min-width:900px){.hero-grid{grid-template-columns:1fr;gap:34px}.hero-copy{max-width:760px}.workboard{max-width:none}.board-main{grid-template-columns:170px 1fr}.work{padding:25px}.work article{grid-template-columns:36px 1fr auto;font-size:14px}}';document.head.append(style);
